/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportWWEmbalagem-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&EmbNom.IsEmpty() AND &EmbCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Descrição") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&EmbNom) WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "Código") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Number = &EmbCod EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'EMBUND' &EmbUnd1.FromString(&GridStateDynamicFilter.Value) If not &EmbUnd1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Und." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&EmbUnd1) EndIf Case &DynamicFiltersSelector1 = !'EMBESP' &EmbEsp1.FromString(&GridStateDynamicFilter.Value) If not &EmbEsp1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Espécie" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True If Not &EmbEsp1.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &EmbEsp1.EnumerationDescription() Endif EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'EMBUND' &EmbUnd2.FromString(&GridStateDynamicFilter.Value) If not &EmbUnd2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Und." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&EmbUnd2) EndIf Case &DynamicFiltersSelector2 = !'EMBESP' &EmbEsp2.FromString(&GridStateDynamicFilter.Value) If not &EmbEsp2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Espécie" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True If Not &EmbEsp2.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &EmbEsp2.EnumerationDescription() Endif EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'EMBUND' &EmbUnd3.FromString(&GridStateDynamicFilter.Value) If not &EmbUnd3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Und." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&EmbUnd3) EndIf Case &DynamicFiltersSelector3 = !'EMBESP' &EmbEsp3.FromString(&GridStateDynamicFilter.Value) If not &EmbEsp3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Espécie" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True If Not &EmbEsp3.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &EmbEsp3.EnumerationDescription() Endif EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Codigo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Descrição Embalagem" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "Qtd." &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "UND" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Espécie"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod EmbCod when &OrderedBy = 1 order EmbCod when &OrderedBy = 2 AND &OrderedDsc = False order (EmbCod) when &OrderedBy = 2 AND &OrderedDsc = True order EmbNom when &OrderedBy = 3 AND &OrderedDsc = False order (EmbNom) when &OrderedBy = 3 AND &OrderedDsc = True order EmbQtd when &OrderedBy = 4 AND &OrderedDsc = False order (EmbQtd) when &OrderedBy = 4 AND &OrderedDsc = True order EmbUnd when &OrderedBy = 5 AND &OrderedDsc = False order (EmbUnd) when &OrderedBy = 5 AND &OrderedDsc = True order EmbEsp when &OrderedBy = 6 AND &OrderedDsc = False order (EmbEsp) when &OrderedBy = 6 AND &OrderedDsc = True
using DSWWEmbalagem(&EmbNom, &EmbCod, &DynamicFiltersSelector1, &EmbUnd1, &EmbEsp1, &DynamicFiltersEnabled2 , &DynamicFiltersSelector2, &EmbUnd2, &EmbEsp2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &EmbUnd3 , &EmbEsp3)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Number = EmbCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(EmbNom) &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Number = EmbQtd &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = WWP_Export_SecureText(EmbUnd) &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = EmbEsp.EnumerationDescription()
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWEmbalagemGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWEmbalagemGridState")) Else &GridState.FromXml(&Session.Get(!"WWEmbalagemGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"EMBNOM" &EmbNom.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"EMBCOD" &EmbCod.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforeWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

parm(out:&Filename, out:&ErrorMessage);

	/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
